def allow(self, client_id: str) -> bool:
    now = time.time()
    if client_id in self._first_request:
        elapsed = now - self._first_request[client_id]
        if elapsed > self.window:
            # Reset window
            self._counts[client_id] = 0
            self._first_request[client_id] = now
    else:
        self._first_request[client_id] = now
    self._counts[client_id] += 1
    return self._counts[client_id] <= self.max_requests
